675→    @Suppress("deprecation") // super.onActivityResult
676→    public override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
677→        super.onActivityResult(requestCode, resultCode, data)
678→        if (resultCode == DeckPicker.RESULT_DB_ERROR) {
679→            closeReviewer(DeckPicker.RESULT_DB_ERROR)
680→        }
681→        if (resultCode == DeckPicker.RESULT_MEDIA_EJECTED) {
682→            finishNoStorageAvailable()
683→        }
684→
685→        /* Reset the schedule and reload the latest card off the top of the stack if required.
686→           The card could have been rescheduled, the deck could have changed, or a change of
687→           note type could have lead to the card being deleted */
688→        val reloadRequired = data?.getBooleanExtra("reloadRequired", false) == true
689→        if (reloadRequired) {
690→            performReload()
691→        }
692→        if (requestCode == EDIT_CURRENT_CARD) {
693→            if (resultCode == RESULT_OK) {
694→                // content of note was changed so update the note and current card
695→                Timber.i("AbstractFlashcardViewer:: Saving card...")
696→                launchCatchingTask { saveEditedCard() }
697→                onEditedNoteChanged()
698→            } else if (resultCode == RESULT_CANCELED && !reloadRequired) {
699→                // nothing was changed by the note editor so just redraw the card
700→                redrawCard()
701→            }
702→        }
703→    }
